#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
using namespace std;
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,K=25;int a[N],n,k;
LL dp[K][N],*lst,*cur;
struct Mo
{
	int L,R,cnt[N];LL Ans;
	inline void ins(int x){Ans+=(cnt[x]++);}
	inline void del(int x){Ans-=(--cnt[x]);}
	inline LL qry(int l,int r)
	{
		while(L>l)ins(a[--L]);while(R<r)ins(a[++R]);
		while(L<l)del(a[L++]);while(R>r)del(a[R--]);
		return Ans;
	}
}Q;
inline void Solve(int ql=0,int qr=n-1,int l=1,int r=n)
{
	if(ql>qr||l>r)return;int mid=(l+r)>>1;//printf("%d\n",mid);
	LL mn=1e18;int rs=0;rep(ql,qr,i){LL tmp=Q.qry(i+1,mid);lst[i]+tmp<mn?mn=lst[i]+tmp,rs=i:0;}
	cur[mid]=mn;Solve(ql,rs,l,mid-1);Solve(rs,qr,mid+1,r);
}
int main()
{
	memset(dp,0x3f,sizeof(dp));dp[0][0]=0;
	n=read(),k=read();rep(1,n,i)a[i]=read();Q.L=1;LL *tmp;
	lst=dp[1];cur=dp[0];rep(1,k,i)tmp=lst,lst=cur,cur=tmp,Solve();
	printf("%lld\n",cur[n]);return 0;
}
